                router.push('/(tabs)/book');
              }}
            >
              <Text style={styles.cardCTAText}>Get Quote</Text>
              <ArrowRight size={16} color={Colors.accent} />
            </Pressable>
          </View>
        </View>
      ))}

      <View style={styles.customBanner}>
        <Text style={styles.customTitle}>Don't See What You Need?</Text>
